1	type Item = { type: string; cursed?: boolean; enchantment?: number };
2	type Customer = { yearsWithMHPCO: number };
3	type Damage = { itemType: string; amount: number };
4	type Incident = { cause: string; damages: Array<Damage> };
5	type Step = { op: string; items?: Array<Item>; policy?: number; incident?: Incident };
6	type Scenario = { customer?: Customer; steps: Array<Step> };
7	
8	const DEDUCTIBLE_PER_DAMAGE = 100;
9	
10	const PROCESSING_FEE = 5;
11	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
12	const CURSED_SURCHARGE_RATE = 0.5;
13	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
14	const HIGH_ENCHANTMENT_THRESHOLD = 5;
15	const LOYALTY_DISCOUNT_RATE = 0.2;
16	const LOYALTY_YEARS_THRESHOLD = 2;
17	const FOLLOWUP_DISCOUNT_RATE = 0.15;
18	
19	const BASE_PREMIUMS: Record<string, number> = {
20	  sword: 100,
21	  amulet: 60,
22	  staff: 80,
23	  potion: 40,
24	  rune: 25,
25	  moonstone: 25,
26	};
27	
28	const INSURANCE_VALUES: Record<string, number> = {
29	  sword: 1000,
30	  amulet: 600,
31	  staff: 800,
32	  potion: 400,
33	  rune: 250,
34	  moonstone: 250,
35	};
36	
37	const CAP_MULTIPLIER = 2;
38	
39	function computeInsuranceSum(items: Array<Item>): number {
40	  return items.reduce((sum, item) => sum + (INSURANCE_VALUES[item.type] ?? 0), 0);
41	}
42	
43	function withFirstInsuranceSurcharge(basePremium: number): number {
44	  return basePremium + basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
45	}
46	
47	function surchargeIf(condition: boolean, basePremium: number, rate: number): number {
48	  return condition ? basePremium * rate : 0;
49	}
50	
51	function hasEnchantmentAtLeast(item: Item | undefined, threshold: number): boolean {
52	  return (item?.enchantment ?? 0) >= threshold;
53	}
54	
55	function quoteItem(item: Item): number {
56	  const basePremium = BASE_PREMIUMS[item.type];
57	  const cursedSurcharge = surchargeIf(item.cursed === true, basePremium, CURSED_SURCHARGE_RATE);
58	  const highEnchantmentSurcharge = surchargeIf(
59	    hasEnchantmentAtLeast(item, HIGH_ENCHANTMENT_THRESHOLD),
60	    basePremium,
61	    HIGH_ENCHANTMENT_SURCHARGE_RATE,
62	  );
63	  return withFirstInsuranceSurcharge(basePremium) + cursedSurcharge + highEnchantmentSurcharge;
64	}
65	
66	const COMPONENT_TYPES = ["rune", "moonstone"];
67	const BLOCK_OF_THREE_BASE = 60;
68	
69	function countByType(items: Array<Item>): Record<string, number> {
70	  const counts: Record<string, number> = {};
71	  for (const item of items) {
72	    counts[item.type] = (counts[item.type] ?? 0) + 1;
73	  }
74	  return counts;
75	}
76	
77	function isLoyalCustomer(customer: Customer | undefined): boolean {
78	  return (customer?.yearsWithMHPCO ?? 0) >= LOYALTY_YEARS_THRESHOLD;
79	}
80	
81	function quoteItems(items: Array<Item>): { itemsPremium: number; sumOfBases: number } {
82	  const counts = countByType(items);
83	  let itemsPremium = 0;
84	  let sumOfBases = 0;
85	  const bundledTypes = new Set<string>();
86	
87	  for (const componentType of COMPONENT_TYPES) {
88	    if (counts[componentType] === 3) {
89	      itemsPremium += withFirstInsuranceSurcharge(BLOCK_OF_THREE_BASE);
90	      sumOfBases += BLOCK_OF_THREE_BASE;
91	      bundledTypes.add(componentType);
92	    }
93	  }
94	
95	  for (const item of items) {
96	    if (bundledTypes.has(item.type)) continue;
97	    itemsPremium += quoteItem(item);
98	    sumOfBases += BASE_PREMIUMS[item.type];
99	  }
100	
101	  return { itemsPremium, sumOfBases };
102	}
103	
104	type Policy = { items: Array<Item>; capRemaining: number };
105	
106	const HIGH_ENCHANTMENT_REIMBURSEMENT_THRESHOLD = 8;
107	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
108	
109	function computeDamagePayout(damage: Damage, policy: Policy | undefined): number {
110	  const item = policy?.items.find((i) => i.type === damage.itemType);
111	  const reimbursableAmount = hasEnchantmentAtLeast(item, HIGH_ENCHANTMENT_REIMBURSEMENT_THRESHOLD)
112	    ? damage.amount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
113	    : damage.amount;
114	  return Math.max(0, reimbursableAmount - DEDUCTIBLE_PER_DAMAGE);
115	}
116	
117	function computePayout(incident: Incident | undefined, policy: Policy | undefined): number {
118	  const damages = incident?.damages ?? [];
119	  return damages.reduce((total, damage) => total + computeDamagePayout(damage, policy), 0);
120	}
121	
122	type StepResult = { premium?: number; payout?: number; remainingCap?: number };
123	
124	function handleClaim(step: Step, policies: Map<number, Policy>): StepResult {
125	  const policy = policies.get(step.policy ?? 0);
126	  const desired = Math.floor(computePayout(step.incident, policy));
127	  const capRemaining = policy?.capRemaining ?? Infinity;
128	  const actualPayout = Math.min(desired, capRemaining);
129	  const newCapRemaining = capRemaining - actualPayout;
130	  if (policy) policy.capRemaining = newCapRemaining;
131	  return { payout: actualPayout, remainingCap: newCapRemaining };
132	}
133	
134	function handleQuote(
135	  step: Step,
136	  stepIndex: number,
137	  customer: Customer | undefined,
138	  policies: Map<number, Policy>,
139	): StepResult {
140	  const items = step.items ?? [];
141	  policies.set(stepIndex, {
142	    items,
143	    capRemaining: CAP_MULTIPLIER * computeInsuranceSum(items),
144	  });
145	  const { itemsPremium, sumOfBases } = quoteItems(items);
146	  const loyaltyDiscount = isLoyalCustomer(customer) ? sumOfBases * LOYALTY_DISCOUNT_RATE : 0;
147	  const followUpDiscount = stepIndex >= 1 ? sumOfBases * FOLLOWUP_DISCOUNT_RATE : 0;
148	  const premium = Math.ceil(itemsPremium - loyaltyDiscount - followUpDiscount + PROCESSING_FEE);
149	  return { premium };
150	}
151	
152	export function processScenario(scenario: unknown): { results: Array<StepResult> } {
153	  const { customer, steps } = scenario as Scenario;
154	  const policies = new Map<number, Policy>();
155	  const results = steps.map((step, stepIndex) =>
156	    step.op === "claim"
157	      ? handleClaim(step, policies)
158	      : handleQuote(step, stepIndex, customer, policies),
159	  );
160	  return { results };
161	}
